const inputCpf = document.getElementById('inputCpf');
const inputPhone = document.getElementById('inputPhone');
const inputPwd = document.getElementById('inputPassword');
const inputPwdC = document.getElementById('inputPasswordConfirm');
const pwdMeter = document.getElementById('pwdMeter');
const pwdHint = document.getElementById('pwdHint');
const pwdMatchHint = document.getElementById('pwdMatchHint');

inputCpf.addEventListener('input', function() {
    let v = this.value.replace(/\D/g, '');
    if (v.length > 11) v = v.slice(0, 11);
    if (v.length > 9) v = v.replace(/(\d{3})(\d{3})(\d{3})(\d{1,2})/, '$1.$2.$3-$4');
    else if (v.length > 6) v = v.replace(/(\d{3})(\d{3})(\d{1,3})/, '$1.$2.$3');
    else if (v.length > 3) v = v.replace(/(\d{3})(\d{1,3})/, '$1.$2');
    this.value = v;
});

inputPhone.addEventListener('input', function() {
    let v = this.value.replace(/\D/g, '');
    if (v.length > 11) v = v.slice(0, 11);
    if (v.length > 10) v = v.replace(/(\d{2})(\d{5})(\d{1,4})/, '($1) $2-$3');
    else if (v.length > 6) v = v.replace(/(\d{2})(\d{4})(\d{1,4})/, '($1) $2-$3');
    else if (v.length > 2) v = v.replace(/(\d{2})(\d{1,5})/, '($1) $2');
    this.value = v;
});

function evalPasswordStrength(pwd) {
    let s = 0;
    if (pwd.length >= 8) s++;
    if (/[a-z]/.test(pwd) && /[A-Z]/.test(pwd)) s++;
    if (/\d/.test(pwd)) s++;
    if (/[^A-Za-z0-9]/.test(pwd) || pwd.length >= 12) s++;
    return Math.min(4, s);
}

inputPwd.addEventListener('input', function() {
    const s = evalPasswordStrength(this.value);
    pwdMeter.dataset.strength = s;
    const labels = ['Muito fraca', 'Fraca', 'Razoável', 'Boa', 'Excelente'];
    pwdHint.querySelector('span').textContent = this.value.length === 0
        ? 'Use ao menos 8 caracteres com letras e números.'
        : `Força: ${labels[s]}.`;
    checkPasswordMatch();
});

function checkPasswordMatch() {
    if (!inputPwdC.value) {
        pwdMatchHint.style.display = 'none';
        return;
    }
    pwdMatchHint.style.display = '';
    if (inputPwdC.value === inputPwd.value) {
        pwdMatchHint.classList.add('match');
        pwdMatchHint.classList.remove('nomatch');
        pwdMatchHint.querySelector('i').className = 'fa-solid fa-circle-check';
        pwdMatchHint.querySelector('span').textContent = 'Senhas coincidem.';
    } else {
        pwdMatchHint.classList.add('nomatch');
        pwdMatchHint.classList.remove('match');
        pwdMatchHint.querySelector('i').className = 'fa-solid fa-circle-xmark';
        pwdMatchHint.querySelector('span').textContent = 'As senhas não coincidem.';
    }
}
inputPwdC.addEventListener('input', checkPasswordMatch);

function validarCPF(cpf) {
    cpf = cpf.replace(/\D/g, '');
    if (cpf.length !== 11) return false;
    if (/^(\d)\1{10}$/.test(cpf)) return false;
    for (var t = 9; t < 11; t++) {
        var d = 0;
        for (var c = 0; c < t; c++) d += parseInt(cpf.charAt(c)) * ((t + 1) - c);
        d = ((10 * d) % 11) % 10;
        if (parseInt(cpf.charAt(t)) !== d) return false;
    }
    return true;
}

document.getElementById('formCadastro').addEventListener('submit', function(e) {
    const cpfVal = inputCpf.value.replace(/\D/g, '');
    if (!validarCPF(cpfVal)) {
        e.preventDefault();
        Swal.fire({icon:'warning',title:LANG.register_cpf_invalid_title,text:LANG.register_cpf_invalid_text,confirmButtonColor:'#16A34A'});
        inputCpf.focus();
        return;
    }
    if (inputPwd.value.length < 8) {
        e.preventDefault();
        Swal.fire({icon:'warning',title:'Senha muito curta',text:'Use pelo menos 8 caracteres.',confirmButtonColor:'#16A34A'});
        inputPwd.focus();
        return;
    }
    if (inputPwd.value !== inputPwdC.value) {
        e.preventDefault();
        Swal.fire({icon:'warning',title:'Senhas diferentes',text:'A confirmação não confere com a senha digitada.',confirmButtonColor:'#16A34A'});
        inputPwdC.focus();
        return;
    }
});
</script>
